import{Q as p,a as i}from"./QBreadcrumbs-xfjtT3wh.js";import{d as u,e as g,o as r,w as a,g as o,f as e,x as l,U as n,T as d,h as v,q,R as f,S as b,K as x,l as P,_}from"./index-Q-7OH7vz.js";import{Q as h}from"./QPage-CTx9ZOAX.js";const y={class:"q-py-xl bg-grey-10"},C={class:"container q-mx-auto text-center"},D={class:"q-py-xl"},z={class:"container q-mx-auto",style:{"max-width":"900px"}},L={class:"privacy-content"},S={class:"text-h5 text-weight-bold q-mb-md"},k=["innerHTML"],w={class:"row q-gutter-md"},Q="Janeiro de 2024",A=u({__name:"PrivacyPage",setup(B){const c=[{title:"1. Introdução",content:`
      <p>O MaintOS ("nós", "nosso" ou "Empresa") está comprometido em proteger a privacidade dos usuários
      de nossa plataforma. Esta Política de Privacidade explica como coletamos, usamos, divulgamos e
      protegemos suas informações pessoais.</p>
      <p class="q-mt-md">Ao utilizar nossos serviços, você concorda com as práticas descritas nesta política.</p>
    `},{title:"2. Dados Coletados",content:`
      <p>Coletamos os seguintes tipos de dados:</p>
      <p class="q-mt-md"><strong>Dados fornecidos por você:</strong></p>
      <ul class="q-mt-sm q-pl-lg">
        <li>Nome completo e e-mail corporativo</li>
        <li>Número de telefone/WhatsApp</li>
        <li>Dados da empresa (razão social, CNPJ)</li>
        <li>Informações de chamados e ordens de serviço</li>
        <li>Fotos e documentos enviados ao sistema</li>
      </ul>
      <p class="q-mt-md"><strong>Dados coletados automaticamente:</strong></p>
      <ul class="q-mt-sm q-pl-lg">
        <li>Endereço IP e dados de navegação</li>
        <li>Geolocalização (quando autorizada)</li>
        <li>Informações do dispositivo</li>
        <li>Logs de acesso e atividades</li>
      </ul>
    `},{title:"3. Finalidade do Tratamento",content:`
      <p>Utilizamos seus dados para:</p>
      <ul class="q-mt-sm q-pl-lg">
        <li><strong>Prestação do serviço:</strong> Gerenciar chamados, ordens de serviço e operações de manutenção</li>
        <li><strong>Comunicação:</strong> Enviar notificações, alertas e atualizações sobre o serviço</li>
        <li><strong>Segurança:</strong> Autenticação, auditoria e prevenção de fraudes</li>
        <li><strong>Melhoria do serviço:</strong> Análise de uso e desenvolvimento de novas funcionalidades</li>
        <li><strong>Obrigações legais:</strong> Cumprimento de requisitos legais e regulatórios</li>
      </ul>
    `},{title:"4. Base Legal (LGPD)",content:`
      <p>O tratamento de dados é realizado com base nas seguintes hipóteses legais previstas na LGPD:</p>
      <ul class="q-mt-sm q-pl-lg">
        <li><strong>Execução de contrato:</strong> Para prestação dos serviços contratados</li>
        <li><strong>Consentimento:</strong> Para funcionalidades opcionais como geolocalização</li>
        <li><strong>Legítimo interesse:</strong> Para melhorias e segurança do serviço</li>
        <li><strong>Cumprimento de obrigação legal:</strong> Para atender requisitos regulatórios</li>
      </ul>
    `},{title:"5. Compartilhamento de Dados",content:`
      <p>Seus dados podem ser compartilhados com:</p>
      <ul class="q-mt-sm q-pl-lg">
        <li><strong>Sua empresa:</strong> Gestores e supervisores autorizados</li>
        <li><strong>Prestadores de serviço:</strong> Provedores de infraestrutura cloud, analytics e comunicação</li>
        <li><strong>Autoridades:</strong> Quando exigido por lei ou ordem judicial</li>
      </ul>
      <p class="q-mt-md"><strong>Não vendemos seus dados pessoais a terceiros.</strong></p>
    `},{title:"6. Armazenamento e Segurança",content:`
      <p>Implementamos medidas técnicas e organizacionais para proteger seus dados:</p>
      <ul class="q-mt-sm q-pl-lg">
        <li>Criptografia de dados em trânsito (TLS/SSL) e em repouso</li>
        <li>Controle de acesso baseado em funções (RBAC)</li>
        <li>Logs de auditoria imutáveis</li>
        <li>Backups automáticos com redundância geográfica</li>
        <li>Monitoramento 24/7 de segurança</li>
      </ul>
      <p class="q-mt-md">Os dados são armazenados em servidores da Cloudflare com replicação global.</p>
    `},{title:"7. Retenção de Dados",content:`
      <p>Mantemos seus dados pelo tempo necessário para:</p>
      <ul class="q-mt-sm q-pl-lg">
        <li>Prestação do serviço contratado</li>
        <li>Cumprimento de obrigações legais (até 5 anos após encerramento)</li>
        <li>Defesa em processos judiciais ou administrativos</li>
      </ul>
      <p class="q-mt-md">Após o encerramento da conta, os dados são anonimizados ou excluídos, salvo obrigações legais.</p>
    `},{title:"8. Seus Direitos (LGPD)",content:`
      <p>Conforme a LGPD, você tem direito a:</p>
      <ul class="q-mt-sm q-pl-lg">
        <li><strong>Acesso:</strong> Solicitar cópia dos seus dados pessoais</li>
        <li><strong>Correção:</strong> Corrigir dados incompletos ou desatualizados</li>
        <li><strong>Eliminação:</strong> Solicitar exclusão de dados desnecessários</li>
        <li><strong>Portabilidade:</strong> Receber seus dados em formato estruturado</li>
        <li><strong>Revogação:</strong> Revogar consentimento a qualquer momento</li>
        <li><strong>Oposição:</strong> Opor-se a tratamento baseado em legítimo interesse</li>
      </ul>
      <p class="q-mt-md">Para exercer seus direitos, entre em contato com nosso DPO.</p>
    `},{title:"9. Cookies e Tecnologias Similares",content:`
      <p>Utilizamos cookies e tecnologias similares para:</p>
      <ul class="q-mt-sm q-pl-lg">
        <li><strong>Cookies essenciais:</strong> Necessários para funcionamento do sistema</li>
        <li><strong>Cookies de preferências:</strong> Lembrar suas configurações</li>
        <li><strong>Cookies de analytics:</strong> Entender como você usa o serviço</li>
      </ul>
      <p class="q-mt-md">Você pode configurar seu navegador para recusar cookies, mas isso pode afetar funcionalidades.</p>
    `},{title:"10. Alterações nesta Política",content:`
      <p>Podemos atualizar esta política periodicamente. Notificaremos sobre alterações significativas
      por e-mail ou através do sistema.</p>
      <p class="q-mt-md">Recomendamos revisar esta página regularmente.</p>
    `}];return(E,s)=>(r(),g(h,{class:"bg-dark text-white"},{default:a(()=>[o("section",y,[o("div",C,[e(p,{class:"q-mb-lg justify-center","active-color":"primary"},{default:a(()=>[e(i,{label:"Home",to:"/"}),e(i,{label:"Política de Privacidade"})]),_:1}),s[0]||(s[0]=o("h1",{class:"text-h2 text-weight-bold q-mb-md"},"Política de Privacidade",-1)),o("p",{class:"text-body1 text-grey-5"}," Última atualização: "+l(Q))])]),o("section",D,[o("div",z,[e(n,{class:"bg-grey-9 no-shadow q-mb-xl"},{default:a(()=>[e(d,{class:"row items-center q-gutter-md"},{default:a(()=>[e(v,{name:"verified_user",color:"positive",size:"3rem"}),s[1]||(s[1]=o("div",null,[o("div",{class:"text-h6 text-weight-bold"},"Conformidade com a LGPD"),o("div",{class:"text-body2 text-grey-5"}," Nossa política está em conformidade com a Lei Geral de Proteção de Dados (Lei nº 13.709/2018). ")],-1))]),_:1})]),_:1}),o("div",L,[(r(),q(f,null,b(c,(t,m)=>o("div",{key:m,class:"q-mb-xl"},[o("h2",S,l(t.title),1),o("div",{class:"text-body1 text-grey-4",innerHTML:t.content},null,8,k)])),64))]),e(x,{dark:"",class:"q-my-xl"}),e(n,{class:"bg-grey-9 no-shadow"},{default:a(()=>[e(d,null,{default:a(()=>[s[2]||(s[2]=o("div",{class:"text-h6 text-weight-bold q-mb-sm"},"Encarregado de Proteção de Dados (DPO)",-1)),s[3]||(s[3]=o("p",{class:"text-body2 text-grey-5 q-mb-md"}," Para exercer seus direitos ou esclarecer dúvidas sobre o tratamento de seus dados, entre em contato com nosso DPO: ",-1)),o("div",w,[e(P,{flat:"",color:"primary",label:"privacidade@maintos.com.br",icon:"email",href:"mailto:privacidade@maintos.com.br"})])]),_:1})]),_:1})])])]),_:1}))}}),I=_(A,[["__scopeId","data-v-ba1a20ad"]]);export{I as default};
